s_c__Content_Markdown__c:
{%- comment -%} Using AI to Build & Migrate StoreConnect Sites — LMS (dashboard + lesson player, all in page body) {%- endcomment -%}
{%- assign total = 4 -%}
{%- comment -%} default to '' BEFORE unescape: unescape(nil) prints empty but errors on `!= blank` comparison, which silently zeroes any enclosing {% if %} tag. {%- endcomment -%}
{%- assign lesson_param = current_request.params.lesson | default: '' | unescape -%}
{%- assign step_param = current_request.params.step | default: '' | unescape -%}

{%- comment -%} access state + this customer's progress row {%- endcomment -%}
{%- assign access_state = 'public' -%}
{%- if current_customer != blank -%}
  {%- assign access_state = 'logged_in' -%}
  {% query 'Contact' as me, email: current_customer.email %}{%- assign me1 = me | first -%}
  {% query 'Lesson_Progress__c' as prog, contact__c: me1.sfid %}{%- assign pcp = prog | first -%}
  {%- if pcp != blank -%}{%- assign access_state = 'member' -%}{%- endif -%}
{%- endif -%}

{%- comment -%} course category + lesson junctions (shared) {%- endcomment -%}
{% query 's_c__Article_Category__c' as cc, name: 'Using AI to Build & Migrate StoreConnect Sites' %}{%- assign cat = cc | first -%}
{% query 's_c__Articles_Article_Categories__c' as juncs, s_c__category_id__c: cat.sfid %}

{%- if lesson_param != blank -%}
{%- comment -%} ===================== LESSON PLAYER ===================== {%- endcomment -%}
  {%- assign n = lesson_param | plus: 0 -%}
  {%- assign step = step_param | plus: 0 -%}
  {%- if step < 1 -%}{%- assign step = 1 -%}{%- endif -%}
  {%- assign art = blank -%}
  {%- for j in juncs -%}
    {% query 's_c__Article__c' as aq, sfid: j.s_c__article_id__c %}{%- assign cand = aq | first -%}
    {%- assign cseq = cand.custom_data['sequence__c'] | floor -%}
    {%- if cseq == n -%}{%- assign art = cand -%}{%- endif -%}
  {%- endfor -%}

  <div class="lms-player" style="max-width:760px;margin:0 auto;">
  {%- if art == blank -%}
    <p>Lesson not found. <a href="?">&larr; Back to course</a></p>
  {%- else -%}
    {%- assign sec1 = art.custom_data['s_c__body_markdown__c'] -%}
    {%- assign sec2 = art.custom_data['content_body_2_markdown__c'] -%}
    {%- assign sec3 = art.custom_data['content_body_3_markdown__c'] -%}
    {%- assign sec4 = art.custom_data['content_body_4_markdown__c'] -%}
    {%- assign sec5 = art.custom_data['content_body_5_markdown__c'] -%}
    {%- assign sec6 = art.custom_data['content_body_6_markdown__c'] -%}
    {%- assign nsteps = 1 -%}
    {%- if sec2 != blank -%}{%- assign nsteps = 2 -%}{%- endif -%}
    {%- if sec3 != blank -%}{%- assign nsteps = 3 -%}{%- endif -%}
    {%- if sec4 != blank -%}{%- assign nsteps = 4 -%}{%- endif -%}
    {%- if sec5 != blank -%}{%- assign nsteps = 5 -%}{%- endif -%}
    {%- if sec6 != blank -%}{%- assign nsteps = 6 -%}{%- endif -%}
    {%- if step > nsteps -%}{%- assign step = nsteps -%}{%- endif -%}
    {%- assign cur = sec1 -%}
    {%- if step == 2 -%}{%- assign cur = sec2 -%}{%- elsif step == 3 -%}{%- assign cur = sec3 -%}{%- elsif step == 4 -%}{%- assign cur = sec4 -%}{%- elsif step == 5 -%}{%- assign cur = sec5 -%}{%- elsif step == 6 -%}{%- assign cur = sec6 -%}{%- endif -%}

    {%- comment -%} progress metrics: within-lesson (section) + whole-course {%- endcomment -%}
    {%- assign sec_pct = step | times: 100 | divided_by: nsteps -%}
    {%- assign done = 0 -%}
    {%- for n2 in (1..total) -%}
      {%- assign s2c = n2 | prepend: '0' | slice: -2, 2 -%}
      {%- assign k2 = 'lesson_' | append: s2c | append: '_progress__c' -%}
      {%- if pcp.custom_data[k2] == 'Completed' -%}{%- assign done = done | plus: 1 -%}{%- endif -%}
    {%- endfor -%}
    {%- assign course_pct = done | times: 100 | divided_by: total -%}

    {%- comment -%} ----- player CSS: matured progress, top/bottom nav buttons, font scaler ----- {%- endcomment -%}
    <style>
      .lms-player{--lms-fs:1.05rem;}
      .lms-toolbar{display:flex;justify-content:space-between;align-items:center;gap:1rem;margin-bottom:1.1rem;}
      .lms-back{color:#6b7280;text-decoration:none;font-size:.92em;}
      .lms-back:hover{color:#111827;}
      .lms-fs{display:inline-flex;align-items:center;gap:.4rem;}
      .lms-fs_label{font-size:.7em;color:#9ca3af;text-transform:uppercase;letter-spacing:.05em;}
      .lms-fs button{min-width:34px;height:30px;border:1px solid #d1d5db;background:#fff;border-radius:6px;cursor:pointer;color:#374151;line-height:1;padding:0 .4rem;}
      .lms-fs button:hover{background:#f3f4f6;}
      .lms-fs button[data-fs=dec]{font-size:.82em;}
      .lms-fs button[data-fs=inc]{font-size:1.05em;font-weight:600;}
      .lms-prog{margin-bottom:1.3rem;}
      .lms-prog_row{display:flex;justify-content:space-between;align-items:center;font-size:.78em;color:#6b7280;margin-bottom:.45rem;}
      .lms-prog_row strong{color:#111827;}
      .lms-segs{display:flex;gap:5px;margin-bottom:1rem;}
      .lms-seg{flex:1;height:8px;border-radius:5px;background:#e5e7eb;transition:background .25s;}
      .lms-seg.is-done{background:linear-gradient(90deg,#15803d,#22c55e);}
      .lms-seg.is-prog{background:linear-gradient(90deg,#1d4ed8,#3b82f6);}
      .lms-seg.is-current{outline:2px solid #111827;outline-offset:2px;}
      .lms-track{height:8px;background:#e5e7eb;border-radius:5px;overflow:hidden;box-shadow:inset 0 1px 2px rgba(0,0,0,.08);}
      .lms-fill{height:100%;background:linear-gradient(90deg,#15803d,#22c55e);border-radius:5px;transition:width .35s cubic-bezier(.4,0,.2,1);}
      .lms-nav{display:flex;justify-content:space-between;align-items:center;gap:.75rem;}
      .lms-nav--top{margin:0 0 1.4rem;}
      .lms-nav--bottom{margin-top:2rem;padding-top:1.1rem;border-top:1px solid #e5e7eb;}
      .lms-nav_step{font-size:.78em;color:#9ca3af;text-transform:uppercase;letter-spacing:.04em;}
      .lms-btn{display:inline-flex;align-items:center;gap:.35rem;padding:.55rem 1.1rem;border-radius:7px;font:inherit;font-weight:600;cursor:pointer;text-decoration:none;border:1px solid transparent;transition:background .12s;}
      .lms-btn--prev{background:#fff;border-color:#d1d5db;color:#374151;}
      .lms-btn--prev:hover{background:#f3f4f6;}
      .lms-btn--next{background:#16a34a;color:#fff;}
      .lms-btn--next:hover{background:#15803d;}
      .lms-btn--disabled{opacity:.4;pointer-events:none;}
      .lms-section{font-size:var(--lms-fs,1.05rem);}
      /* floating text-size control: fixed to the viewport so it stays reachable while scrolling */
      /* single rounded rectangle: [ - ] A [ + ], each cell flex-centered */
      .lms-fsbar{position:fixed;right:16px;bottom:16px;z-index:9999;display:inline-flex;align-items:stretch;background:#fff;border:1px solid #d1d5db;border-radius:10px;box-shadow:0 4px 16px rgba(0,0,0,.18);overflow:hidden;}
      .lms-fsbar button{display:flex;align-items:center;justify-content:center;width:44px;height:40px;border:0;background:#fff;cursor:pointer;color:#374151;font-size:1.3em;line-height:1;padding:0;}
      .lms-fsbar button:hover{background:#f3f4f6;}
      .lms-fsbar_a{display:flex;align-items:center;justify-content:center;width:38px;font-weight:700;color:#111827;border-left:1px solid #e5e7eb;border-right:1px solid #e5e7eb;}
    </style>

    {%- comment -%} ----- top toolbar (back) + floating text-size scaler (stays in view on scroll) ----- {%- endcomment -%}
    <div class="lms-toolbar">
      <a class="lms-back" href="?">&larr; Back to course</a>
    </div>
    <div class="lms-fsbar" role="group" aria-label="Text size">
      <button type="button" data-fs="dec" aria-label="Decrease text size">&minus;</button>
      <span class="lms-fsbar_a" aria-hidden="true">A</span>
      <button type="button" data-fs="inc" aria-label="Increase text size">+</button>
    </div>

    {%- comment -%} ----- progress: whole-course segment strip + within-lesson bar ----- {%- endcomment -%}
    <div class="lms-prog">
      <div class="lms-prog_row">
        <span>Lesson <strong>{{ n }}</strong> of {{ total }}</span>
        {%- if access_state == 'member' -%}<span>{{ done }}/{{ total }} complete &middot; {{ course_pct }}%</span>{%- endif -%}
      </div>
      <div class="lms-segs">
      {%- for n2 in (1..total) -%}
        {%- assign s2c = n2 | prepend: '0' | slice: -2, 2 -%}
        {%- assign k2 = 'lesson_' | append: s2c | append: '_progress__c' -%}
        {%- assign st2 = pcp.custom_data[k2] -%}
        {%- assign cls = '' -%}
        {%- if st2 == 'Completed' -%}{%- assign cls = 'is-done' -%}{%- elsif st2 == 'In Progress' -%}{%- assign cls = 'is-prog' -%}{%- endif -%}
        {%- if n2 == n -%}{%- assign cls = cls | append: ' is-current' -%}{%- endif -%}
        <div class="lms-seg {{ cls }}" title="Lesson {{ n2 }}"></div>
      {%- endfor -%}
      </div>
      <div class="lms-prog_row"><span>Section {{ step }} of {{ nsteps }}</span><span>{{ sec_pct }}%</span></div>
      <div class="lms-track" role="progressbar" aria-valuemin="0" aria-valuemax="100" aria-valuenow="{{ sec_pct }}"><div class="lms-fill" style="width:{{ sec_pct }}%;"></div></div>
    </div>

    {%- comment -%} ----- top nav ----- {%- endcomment -%}
    <nav class="lms-nav lms-nav--top" aria-label="Section navigation (top)">
      {%- if step > 1 -%}<a class="lms-btn lms-btn--prev" href="?lesson={{ n }}&step={{ step | minus: 1 }}">&larr; Previous</a>{%- else -%}<span class="lms-btn lms-btn--prev lms-btn--disabled" aria-disabled="true">&larr; Previous</span>{%- endif -%}
      <span class="lms-nav_step">Section {{ step }} / {{ nsteps }}</span>
      {%- if step < nsteps -%}<a class="lms-btn lms-btn--next" href="?lesson={{ n }}&step={{ step | plus: 1 }}">Next &rarr;</a>{%- else -%}<a class="lms-btn lms-btn--next" href="?">Finish &rarr;</a>{%- endif -%}
    </nav>

    <h1 style="margin:.2rem 0 1.1rem;">{{ art.s_c__title__c }}</h1>
    <div class="lms-section" style="line-height:1.65;">
    {%- assign nl = '%0A' | url_decode -%}
    {%- assign rawlines = cur | split: nl -%}
    {%- if cur contains '- [' -%}
    {%- comment -%} ===== interactive self-scored quiz (simple-lms kit pattern) ===== {%- endcomment -%}
    <style>
      .lms-quiz{margin:1rem 0;}
      .lms-quiz_prompt{font-weight:600;margin:1.4rem 0 .5rem;}
      .lms-quiz_opt{display:flex;align-items:flex-start;gap:.6rem;margin:.4rem 0;padding:.55rem .75rem;border:1px solid #e2e6ee;border-radius:8px;cursor:pointer;transition:background .12s;}
      .lms-quiz_opt:hover{background:#f4f6fb;}
      .lms-quiz_opt input{margin-top:.25rem;}
      .lms-quiz_opt .lms-quiz_txt{flex:1;}
      .lms-quiz_mark{margin-left:auto;font-weight:700;}
      .lms-quiz.is-graded .lms-quiz_opt{cursor:default;}
      .lms-quiz.is-graded .lms-quiz_opt.is-correct{background:#e7f6ec;box-shadow:inset 0 0 0 1px #34a853;}
      .lms-quiz.is-graded .lms-quiz_opt.is-wrong{background:#fdeceb;box-shadow:inset 0 0 0 1px #ea4335;}
      .lms-quiz.is-graded .lms-quiz_opt.is-correct .lms-quiz_mark::after{content:"\2713";color:#1e7e34;}
      .lms-quiz.is-graded .lms-quiz_opt.is-wrong .lms-quiz_mark::after{content:"\2717";color:#c5221f;}
      .lms-quiz_actions{margin-top:1.3rem;display:flex;gap:.6rem;align-items:center;flex-wrap:wrap;}
      .lms-quiz_actions button{padding:.55rem 1.1rem;border-radius:6px;border:1px solid #16a34a;background:#16a34a;color:#fff;cursor:pointer;font:inherit;}
      .lms-quiz_actions button[data-act=retry]{background:#fff;color:#374151;border-color:#d1d5db;}
      .lms-quiz_score{font-weight:700;}
    </style>
    <div class="lms-quiz">
    {%- assign qn = 0 -%}
    {%- for ln in rawlines -%}
      {%- assign t = ln | strip -%}
      {%- assign p3 = t | slice: 0, 3 -%}{%- assign p4 = t | slice: 0, 4 -%}{%- assign p6 = t | slice: 0, 6 -%}{%- assign c2 = t | slice: 1, 2 -%}
      {%- if t == '' -%}
      {%- elsif p4 == '### ' -%}<h2 style="margin:.2rem 0 .8rem;font-size:1.3em;">{{ t | remove_first: '### ' }}</h2>
      {%- elsif p3 == '## ' -%}<h2 style="margin:.2rem 0 .8rem;font-size:1.3em;">{{ t | remove_first: '## ' }}</h2>
      {%- elsif p6 == '- [x] ' -%}<label class="lms-quiz_opt" data-q="{{ qn }}" data-correct="1"><input type="radio" name="q{{ qn }}"><span class="lms-quiz_txt">{{ t | remove_first: '- [x] ' }}</span><span class="lms-quiz_mark"></span></label>
      {%- elsif p6 == '- [ ] ' -%}<label class="lms-quiz_opt" data-q="{{ qn }}"><input type="radio" name="q{{ qn }}"><span class="lms-quiz_txt">{{ t | remove_first: '- [ ] ' }}</span><span class="lms-quiz_mark"></span></label>
      {%- elsif c2 == '. ' -%}{%- assign qn = qn | plus: 1 -%}<p class="lms-quiz_prompt">{{ t }}</p>
      {%- else -%}<p style="margin:0 0 .85rem;">{{ t }}</p>
      {%- endif -%}
    {%- endfor -%}
      <div class="lms-quiz_actions">
        <button type="button" data-act="check">Check my answers</button>
        <button type="button" data-act="retry" style="display:none;">Try again</button>
        <span class="lms-quiz_score" aria-live="polite"></span>
      </div>
    </div>
    <script>
    (function(){
      var quiz=document.querySelector('.lms-quiz'); if(!quiz){return;}
      var check=quiz.querySelector('[data-act=check]');
      var retry=quiz.querySelector('[data-act=retry]');
      var score=quiz.querySelector('.lms-quiz_score');
      function groups(){var g={};quiz.querySelectorAll('.lms-quiz_opt').forEach(function(l){var q=l.getAttribute('data-q');if(!g[q]){g[q]=[];}g[q].push(l);});return g;}
      check.addEventListener('click',function(){
        var g=groups();var total=0;var correct=0;
        Object.keys(g).forEach(function(q){
          total++;var sel=null;var key=null;
          g[q].forEach(function(l){l.classList.remove('is-correct','is-wrong');if(l.querySelector('input').checked){sel=l;}if(l.getAttribute('data-correct')){key=l;}});
          if(key){key.classList.add('is-correct');}
          if(sel){if(sel!==key){sel.classList.add('is-wrong');}}
          if(sel===key){correct++;}
        });
        quiz.classList.add('is-graded');
        score.textContent='You scored '+correct+' of '+total;
        check.style.display='none';retry.style.display='';
        var c=document.querySelector('[data-lms-complete]');if(c){c.classList.remove('lms-complete-locked');}
      });
      retry.addEventListener('click',function(){
        quiz.classList.remove('is-graded');
        quiz.querySelectorAll('.lms-quiz_opt').forEach(function(l){l.classList.remove('is-correct','is-wrong');});
        quiz.querySelectorAll('input[type=radio]').forEach(function(r){r.checked=false;});
        score.textContent='';check.style.display='';retry.style.display='none';
      });
    })();
    </script>
    {%- else -%}
    {%- for ln in rawlines -%}
      {%- assign t = ln | strip -%}
      {%- assign p3 = t | slice: 0, 3 -%}{%- assign p4 = t | slice: 0, 4 -%}{%- assign p6 = t | slice: 0, 6 -%}{%- assign c2 = t | slice: 1, 2 -%}
      {%- if t == '' -%}
      {%- elsif p6 == '@@IMG:' -%}<figure style="margin:0 0 1.1rem;"><img src="{{ t | remove_first: '@@IMG:' }}" alt="Course visual" style="width:100%;border-radius:8px;display:block;" /></figure>
      {%- elsif p6 == '@@AUD:' -%}<audio controls preload="none" src="{{ t | remove_first: '@@AUD:' }}" style="width:100%;margin:0 0 1.1rem;"></audio>
      {%- elsif p4 == '### ' -%}<h3 style="margin:1.2rem 0 .4rem;">{{ t | remove_first: '### ' }}</h3>
      {%- elsif p3 == '## ' -%}<h2 style="margin:.2rem 0 .8rem;font-size:1.3em;">{{ t | remove_first: '## ' }}</h2>
      {%- elsif c2 == '. ' -%}<p style="font-weight:600;margin:1.1rem 0 .4rem;">{{ t }}</p>
      {%- else -%}<p style="margin:0 0 .85rem;">{{ t }}</p>
      {%- endif -%}
    {%- endfor -%}
    {%- endif -%}
    </div>
    {%- comment -%} ----- bottom nav ----- {%- endcomment -%}
    <nav class="lms-nav lms-nav--bottom" aria-label="Section navigation (bottom)">
      {%- if step > 1 -%}<a class="lms-btn lms-btn--prev" href="?lesson={{ n }}&step={{ step | minus: 1 }}">&larr; Previous</a>{%- else -%}<span class="lms-btn lms-btn--prev lms-btn--disabled" aria-disabled="true">&larr; Previous</span>{%- endif -%}
      <span class="lms-nav_step">Section {{ step }} / {{ nsteps }}</span>
      {%- if step < nsteps -%}<a class="lms-btn lms-btn--next" href="?lesson={{ n }}&step={{ step | plus: 1 }}">Next &rarr;</a>{%- else -%}<a class="lms-btn lms-btn--next" href="?">Finish &rarr;</a>{%- endif -%}
    </nav>

    {%- comment -%} ----- text-size scaler (persisted in localStorage) ----- {%- endcomment -%}
    <script>
    (function(){
      var p=document.querySelector('.lms-player'); if(!p){return;}
      var KEY='courseFs'; var sizes=[0.9,1.0,1.05,1.2,1.4]; var i=2;
      try{var s=localStorage.getItem(KEY); if(s!==null){i=parseInt(s,10);}}catch(e){}
      function apply(){ i=Math.max(0,Math.min(sizes.length-1,i)); p.style.setProperty('--lms-fs',sizes[i]+'rem'); try{localStorage.setItem(KEY,i);}catch(e){} }
      p.querySelectorAll('[data-fs=dec]').forEach(function(b){b.addEventListener('click',function(){i=i-1;apply();});});
      p.querySelectorAll('[data-fs=inc]').forEach(function(b){b.addEventListener('click',function(){i=i+1;apply();});});
      apply();
    })();
    </script>
  {%- endif -%}
  </div>

{%- else -%}
{%- comment -%} ===================== DASHBOARD ===================== {%- endcomment -%}
<div class="lms-course" style="max-width:760px;margin:0 auto;">
  <header style="text-align:center;padding:1.25rem 1rem 1.5rem;border-bottom:1px solid #e5e7eb;margin-bottom:1.5rem;">
    <h1 style="margin:.2rem 0;font-size:1.8em;">Using AI to Build &amp; Migrate StoreConnect Sites</h1>
    <p style="color:#6b7280;margin:.25rem 0 0;">Drive an AI coding agent to stand up and migrate a StoreConnect store between orgs.</p>
  </header>

  {%- if access_state == 'member' -%}
    {%- assign done = 0 -%}
    {%- for n in (1..total) -%}
      {%- assign s2 = n | prepend: '0' | slice: -2, 2 -%}
      {%- assign k = 'lesson_' | append: s2 | append: '_progress__c' -%}
      {%- if pcp.custom_data[k] == 'Completed' -%}{%- assign done = done | plus: 1 -%}{%- endif -%}
    {%- endfor -%}
    {%- assign pct = done | times: 100 | divided_by: total -%}
    <div style="margin-bottom:1.5rem;">
      <div style="display:flex;justify-content:space-between;font-size:.9em;margin-bottom:.4rem;"><span><strong>{{ done }}</strong> of {{ total }} complete</span><span style="color:#6b7280;">{{ pct }}%</span></div>
      <div style="height:8px;background:#e5e7eb;border-radius:4px;overflow:hidden;"><div style="width:{{ pct }}%;height:100%;background:#16a34a;"></div></div>
    </div>
  {%- else -%}
    <div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:1rem 1.25rem;margin-bottom:1.5rem;text-align:center;color:#1e3a8a;">
      Preview &mdash; all lessons are open. Progress tracking and sequential unlocking activate once learners are enrolled.
    </div>
  {%- endif -%}

  <div style="display:flex;flex-direction:column;gap:.6rem;">
  {%- for j in juncs -%}
    {% query 's_c__Article__c' as aq, sfid: j.s_c__article_id__c %}{%- assign art = aq | first -%}
    {%- if art != blank -%}
      {%- assign n = art.custom_data['sequence__c'] | floor -%}
      {%- assign s2 = n | prepend: '0' | slice: -2, 2 -%}
      {%- assign k = 'lesson_' | append: s2 | append: '_progress__c' -%}
      {%- assign status = pcp.custom_data[k] -%}
      {%- assign locked = false -%}
      {%- if access_state == 'member' and n > 1 -%}
        {%- assign prior = n | minus: 1 -%}
        {%- for p in (1..prior) -%}
          {%- assign ps2 = p | prepend: '0' | slice: -2, 2 -%}
          {%- assign pk = 'lesson_' | append: ps2 | append: '_progress__c' -%}
          {%- if pcp.custom_data[pk] != 'Completed' -%}{%- assign locked = true -%}{%- endif -%}
        {%- endfor -%}
      {%- endif -%}
      {%- assign glyph = '○' -%}
      {%- if status == 'Completed' -%}{%- assign glyph = '●' -%}{%- elsif status == 'In Progress' -%}{%- assign glyph = '◐' -%}{%- endif -%}
      {%- if locked -%}{%- assign glyph = '🔒' -%}{%- endif -%}
      {%- if locked -%}
        <div style="display:flex;align-items:center;gap:.75rem;padding:.85rem 1rem;border:1px solid #e5e7eb;border-radius:8px;background:#f9fafb;color:#9ca3af;">
          <span style="font-size:1.2em;">{{ glyph }}</span>
          <span style="font-size:.8em;text-transform:uppercase;letter-spacing:.04em;">Lesson {{ n }}</span>
          <strong style="flex:1;">{{ art.s_c__title__c }}</strong>
        </div>
      {%- else -%}
        <a href="?lesson={{ n }}&step=1" style="display:flex;align-items:center;gap:.75rem;padding:.85rem 1rem;border:1px solid #d1d5db;border-radius:8px;background:#fff;text-decoration:none;color:#111;">
          <span style="font-size:1.2em;">{{ glyph }}</span>
          <span style="font-size:.8em;text-transform:uppercase;letter-spacing:.04em;color:#6b7280;">Lesson {{ n }}</span>
          <strong style="flex:1;">{{ art.s_c__title__c }}</strong>
